    99	        var columnIndex = Columns.IndexOf(column);
   100	
   101	        var minWidths = new List<int>();
   102	        var maxWidths = new List<int>();
   103	
   104	        // Include columns (both header and footer) in measurement
   105	        var headerMeasure = column.Header.Measure(Options, maxWidth);
   106	        var footerMeasure = column.Footer?.Measure(Options, maxWidth) ?? headerMeasure;
   107	        minWidths.Add(Math.Min(headerMeasure.Min, footerMeasure.Min));
   108	        maxWidths.Add(Math.Max(headerMeasure.Max, footerMeasure.Max));
   109	
   110	        // Measure rows, accounting for column spanning
   111	        foreach (var row in Rows)
   112	        {
   113	            var currentColumnIndex = 0;
   114	            foreach (var item in row)
   115	            {
   116	                if (currentColumnIndex == columnIndex)
   117	                {
   118	                    // This cell starts at the column we're measuring
   119	                    if (item is TableCell tableCell)
   120	                    {
   121	                        // For spanning cells, distribute the measurement across spanned columns
   122	                        var cellMeasure = tableCell.Content.Measure(Options, maxWidth);
   123	
   124	                        if (tableCell.ColumnSpan > 1)
   125	                        {
   126	                            // Distribute the measurement evenly across spanned columns
   127	                            var minPerColumn = cellMeasure.Min / tableCell.ColumnSpan;
   128	                            var maxPerColumn = cellMeasure.Max / tableCell.ColumnSpan;
   129	                            minWidths.Add(minPerColumn);
   130	                            maxWidths.Add(maxPerColumn);
   131	                        }
   132	                        else
   133	                        {
   134	                            minWidths.Add(cellMeasure.Min);
   135	                            maxWidths.Add(cellMeasure.Max);
   136	                        }
   137	                    }
   138	                    else
   139	                    {
   140	                        var rowMeasure = item.Measure(Options, maxWidth);
   141	                        minWidths.Add(rowMeasure.Min);
   142	                        maxWidths.Add(rowMeasure.Max);
   143	                    }
   144	                    break; // Found the cell for this column, move to next row
   145	                }
   146	                else if (item is TableCell tableCell && currentColumnIndex + tableCell.ColumnSpan > columnIndex)
   147	                {
   148	                    // This column is covered by a spanning cell that started earlier
   149	                    // Contribute a portion of the spanning cell's measurement
   150	                    var cellMeasure = tableCell.Content.Measure(Options, maxWidth);
   151	                    var minPerColumn = cellMeasure.Min / tableCell.ColumnSpan;
   152	                    var maxPerColumn = cellMeasure.Max / tableCell.ColumnSpan;
   153	                    minWidths.Add(minPerColumn);
   154	                    maxWidths.Add(maxPerColumn);
   155	                    break;
   156	                }
   157	
   158	                // Advance column index
   159	                currentColumnIndex += item is TableCell tc ? tc.ColumnSpan : 1;
   160	            }
   161	        }
   162	
   163	        var padding = column.Padding?.GetWidth() ?? 0;
   164	
   165	        return new Measurement(
   166	            minWidths.Count > 0 ? minWidths.Max() : padding,
   167	            maxWidths.Count > 0 ? maxWidths.Max() : maxWidth);
