   170	    // Reduce widths so that the total is less or equal to the max width.
   171	    // Ported from Rich by Will McGugan, licensed under MIT.
   172	    // https://github.com/willmcgugan/rich/blob/527475837ebbfc427530b3ee0d4d0741d2d0fc6d/rich/table.py#L442
   173	    private static List<int> CollapseWidths(List<int> widths, List<bool> wrappable, int maxWidth)
   174	    {
   175	        var totalWidth = widths.Sum();
   176	        var excessWidth = totalWidth - maxWidth;
   177	
   178	        if (wrappable.AnyTrue())
   179	        {
   180	            while (totalWidth != 0 && excessWidth > 0)
   181	            {
   182	                var maxColumn = widths.Zip(wrappable, (first, second) => (width: first, allowWrap: second))
   183	                    .Where(x => x.allowWrap)
   184	                    .Max(x => x.width);
   185	
   186	                var secondMaxColumn = widths.Zip(wrappable, (width, allowWrap) => allowWrap && width != maxColumn ? width : 1).Max();
   187	                var columnDifference = maxColumn - secondMaxColumn;
   188	
   189	                var ratios = widths.Zip(wrappable, (width, allowWrap) => width == maxColumn && allowWrap ? 1 : 0).ToList();
   190	                if (!ratios.Any(x => x != 0) || columnDifference == 0)
   191	                {
   192	                    break;
   193	                }
   194	
   195	                var maxReduce = widths.Select(_ => Math.Min(excessWidth, columnDifference)).ToList();
   196	                widths = Ratio.Reduce(excessWidth, ratios, maxReduce, widths);
   197	
   198	                totalWidth = widths.Sum();
   199	                excessWidth = totalWidth - maxWidth;
   200	            }
   201	        }
   202	
   203	        return widths;
   204	    }
   205	}

