        if (rightEdge < 0)
            rightEdge = lines[i].LastIndexOf('\u256e'); // ╮
        rightBorderPositions.Add(rightEdge >= 0 ? rightEdge : lines[i].Length);
        Console.WriteLine($"  Line {i}: len={lines[i].Length}, rightBorderPos={rightEdge}");
    }
}

var distinctPositions = rightBorderPositions.Distinct().ToList();
if (distinctPositions.Count > 1)
    Console.WriteLine($"FAIL: Right border positions differ: {string.Join(", ", distinctPositions)}");
else if (distinctPositions.Count > 0)
    Console.WriteLine($"PASS: All lines same border position: {distinctPositions[0]}");
