/// <summary>
    /// Splits the segment at the offset.
    /// </summary>
    /// <param name="offset">The offset where to split the segment.</param>
    /// <returns>One or two new segments representing the split.</returns>
    public (Segment First, Segment? Second) Split(int offset)
    {
        if (offset < 0)
        {
            return (this, null);
        }

        if (offset >= CellCount())
        {
            return (this, null);
        }

        var index = 0;
        if (offset > 0)
        {
            var accumulated = 0;
            for (var i = 0; i < Text.Length;)
            {
                var ch = Text[i];

                // Handle surrogate pairs
                if (char.IsHighSurrogate(ch) && i + 1 < Text.Length && char.IsLowSurrogate(Text[i + 1]))
                {
                    var codePoint = char.ConvertToUtf32(ch, Text[i + 1]);
                    accumulated += UnicodeCalculator.GetWidth(codePoint);
                    i += 2;
                    index += 2;
                }
                else if (ch == '\u200D')
                {
                    // Skip ZWJ and the next character
                    i += 2;
                    index += 2;
                }
                else if (ch == '\uFE0F')
                {
                    // Skip VS16
                    i++;
                    index++;
                }
                else
                {
                    accumulated += Cell.GetCellLength(ch);
                    i++;
                    index++;
                }

                if (accumulated >= offset)
                {
                    break;
                }
            }
        }

        return (
            new Segment(Text.Substring(0, index), Style),
            new Segment(Text.Substring(index, Text.Length - index), Style));
    }

