/// <summary>
    /// Truncates the segment to the specified width.
    /// </summary>
    /// <param name="segment">The segment to truncate.</param>
    /// <param name="maxWidth">The maximum width that the segment may occupy.</param>
    /// <returns>A new truncated segment, or <c>null</c>.</returns>
    public static Segment? Truncate(Segment? segment, int maxWidth)
    {
        if (segment is null)
        {
            return null;
        }

        if (segment.CellCount() <= maxWidth)
        {
            return segment;
        }

        var builder = new StringBuilder();
        var accumulatedCellWidth = 0;
        for (var i = 0; i < segment.Text.Length;)
        {
            var ch = segment.Text[i];

            // Handle surrogate pairs
            if (char.IsHighSurrogate(ch) && i + 1 < segment.Text.Length && char.IsLowSurrogate(segment.Text[i + 1]))
            {
                var codePoint = char.ConvertToUtf32(ch, segment.Text[i + 1]);
                var charWidth = UnicodeCalculator.GetWidth(codePoint);
                if (accumulatedCellWidth + charWidth > maxWidth)
                {
                    break;
                }

                builder.Append(ch);
                builder.Append(segment.Text[i + 1]);
                accumulatedCellWidth += charWidth;
                i += 2;
            }
            else if (ch == '\u200D')
            {
                // Skip ZWJ and the next character
                if (accumulatedCellWidth > 0)
                {
                    builder.Append(ch);
                    if (i + 1 < segment.Text.Length)
                    {
                        builder.Append(segment.Text[i + 1]);
                    }
                }

                i += 2;
            }
            else if (ch == '\uFE0F')
            {
                // Skip VS16
                builder.Append(ch);
                i++;
            }
            else
            {
                var characterWidth = UnicodeCalculator.GetWidth(ch);
                if (accumulatedCellWidth + characterWidth > maxWidth)
                {
                    break;
                }

                builder.Append(ch);
                accumulatedCellWidth += characterWidth;
                i++;
            }
        }

        if (builder.Length == 0)
        {
            return null;
        }

        return new Segment(builder.ToString(), segment.Style);
    }

