internal static List<string> SplitSegment(string text, int maxCellLength)
    {
        var list = new List<string>();

        var length = 0;
        var sb = new StringBuilder();
        for (var i = 0; i < text.Length;)
        {
            var ch = text[i];

            // Handle surrogate pairs
            if (char.IsHighSurrogate(ch) && i + 1 < text.Length && char.IsLowSurrogate(text[i + 1]))
            {
                var codePoint = char.ConvertToUtf32(ch, text[i + 1]);
                var w = UnicodeCalculator.GetWidth(codePoint);
                if (length + w > maxCellLength)
                {
                    list.Add(sb.ToString());
                    sb.Clear();
                    length = 0;
                }

                length += w;
                sb.Append(ch);
                sb.Append(text[i + 1]);
                i += 2;
            }
            else if (ch == '\u200D')
            {
                // ZWJ: append and skip next
                sb.Append(ch);
                if (i + 1 < text.Length)
                {
                    sb.Append(text[i + 1]);
                }

                i += 2;
            }
            else if (ch == '\uFE0F')
            {
                // VS16
                sb.Append(ch);
                i++;
            }
            else
            {
                var w = UnicodeCalculator.GetWidth(ch);
                if (length + w > maxCellLength)
                {
                    list.Add(sb.ToString());
                    sb.Clear();
                    length = 0;
                }

                length += w;
                sb.Append(ch);
                i++;
            }
        }

        list.Add(sb.ToString());

        return list;
    }

