                i++;
            }
            else
            {
                var w = UnicodeCalculator.GetWidth(ch);
                if (length + w > maxCellLength)
                {
                    list.Add(sb.ToString());
                    sb.Clear();
                    length = 0;
                }

                length += w;
                sb.Append(ch);
                i++;
            }
        }

        list.Add(sb.ToString());

        return list;
    }

    private class SegmentBuilder
    {
